 } catch (error) {
 console.error(`Error updating incident ${sysId}:`, error)
 throw error
 }
 }

 // Delete an incident
 async delete(sysId) {
 try {
 const response = await fetch(`/api/now/table/${this.tableName}/${sysId}`, {
 method: 'DELETE',
 headers: {
 Accept: 'application/json',
 'X-UserToken': window.g_ck,
 },
 })

 if (!response.ok) {
